import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is a healthy weight?", a: "A healthy weight is a range associated with lower health risk for your height, body composition, and overall health profile." },
  { q: "How do you calculate healthy weight for your height?", a: "A common method uses the BMI range 18.5 to 24.9. Medical ideal-weight formulas can provide additional reference points." },
  { q: "Is BMI an accurate measure of healthy weight?", a: "BMI is useful for screening but does not directly measure muscle, bone, or fat distribution. It should be interpreted with context." },
  { q: "What is the difference between ideal weight and healthy weight?", a: "Healthy weight is usually a range, while ideal weight formulas estimate a single reference weight." },
  { q: "How do you maintain a healthy weight?", a: "Maintain a balanced diet, regular activity, sleep, stress management, and a calorie intake that matches your energy needs." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const lb = (v: number) => `${Math.round(v)} lb`;
function formulas(heightIn: number, gender: string) {
  const over = Math.max(0, heightIn - 60);
  const kgToLb = 2.20462;
  const robinson = (gender === "Male" ? 52 + 1.9 * over : 49 + 1.7 * over) * kgToLb;
  const miller = (gender === "Male" ? 56.2 + 1.41 * over : 53.1 + 1.36 * over) * kgToLb;
  const hamwi = (gender === "Male" ? 106 + 6 * over : 100 + 5 * over);
  const min = 18.5 * heightIn * heightIn / 703;
  const max = 24.9 * heightIn * heightIn / 703;
  return { min, max, robinson, miller, hamwi };
}

export default function HealthyWeightCalculator() {
  const [height, setHeight] = useState(68);
  const [gender, setGender] = useState("Male");
  const result = useMemo(() => formulas(height, gender), [height, gender]);
  const rows = Array.from({ length: 9 }, (_, i) => 60 + i * 2).map((h) => [h, 18.5 * h * h / 703, 24.9 * h * h / 703, 25 * h * h / 703, 30 * h * h / 703]);
  return (
    <>
      <SEOHead title="Free Healthy Weight Calculator Online - Find Your Ideal Healthy Weight Range Instantly | CalcHive" description="Free online healthy weight calculator. Find your healthy weight range based on height using BMI and medical formulas for men and women instantly. 100% free, no signup required." canonical="/healthy-weight-calculator" keywords="free healthy weight calculator, healthy weight range calculator free online, ideal weight for height calculator free, normal weight calculator free, healthy BMI weight calculator free" category="Health Calculators" breadcrumbName="Free Healthy Weight Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Healthy Weight Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Find your healthy BMI weight range and compare Robinson, Miller, and Hamwi ideal weight formulas.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Height (in)</label><input type="number" value={height} onChange={(e) => setHeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Gender</label><select value={gender} onChange={(e) => setGender(e.target.value)} className={inputClass}><option>Male</option><option>Female</option></select></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Healthy Weight Range</p><p className="text-5xl sm:text-6xl font-black text-white">{lb(result.min)}-{lb(result.max)}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4">{[["Robinson", result.robinson], ["Miller", result.miller], ["Hamwi", result.hamwi]].map(([label, value]) => <div key={String(label)} className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">{label}</p><p className="text-lg font-extrabold">{lb(Number(value))}</p></div>)}</div></section><MedicalDisclaimer /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Your Healthy Weight Range for Free</h2><p className="text-muted-foreground leading-relaxed">The BMI method converts the healthy BMI range of 18.5 to 24.9 into a weight range for your height.</p><h2 className="text-2xl font-bold">What Is a Healthy Weight for Your Height</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Healthy Weight Range by Height</caption><thead className="bg-muted/60"><tr>{["Height", "Min Healthy Weight", "Max Healthy Weight", "Overweight Starts At", "Obese Starts At"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((r) => <tr key={r[0]}><td className="py-2.5 px-3 font-semibold">{Math.floor(r[0] / 12)}ft {r[0] % 12}in</td>{r.slice(1).map((v) => <td key={v} className="py-2.5 px-3">{lb(v)}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free Ideal Body Weight Range Tool for Men and Women</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/healthy-weight-calculator" headingLevel="h3" /></main>
    </>
  );
}


